solution_code:
#include <iostream>

class DynArray {
public:
    int* items;
    int  size;

    DynArray(int n) : size{n} {
        items = new int[n]{};
    }

    ~DynArray() {
        delete[] items;
    }
};

int load() {
    int n;
    std::cin >> n;
    DynArray arr{n};
    for (int i = 0; i < n; ++i)
        std::cin >> arr.items[i];
    return arr.items[0];
}

int main() {
    std::cout << "First: " << load() << "\n";
    return 0;
}
